<Stats id="monster-anemos--stats" atts={[18,31,30,23,26,31]} bab={22} cmb={26} cmd={57} feats={["Combat Reflexes","Deadly Aim","Flyby Attack",["Improved Critical"," (kinetic blast)"],"Improved Critical (spear)","Improved Initiative","Improved Iron Will","Improved Precise Shot","Iron Will","Point-Blank Shot","Precise Shot"]} skills={{"acro":{"b":35},"fly":{"b":43},"k":{"g":31,"n":31},"per":{"b":33},"umd":{"b":35}}} lang={["Aq","Au","C","Ig","S","T"]} sq={<>manifest thunderbolt, utility wild talents (<Link to="/kinetic/airs_reach">air's reach</Link>, <Link to="/kinetic/greater_windsight">greater windsight</Link>, <Link to="/kinetic/ride_the_blast">ride the blast</Link>, <Link to="/kinetic/windsight">windsight</Link>), wind form</>} />
