<Offense id="monster-atuikakura--offense" sp={10} sw={120} melee={<>bite +27 (3d6+13 plus poison), slam +27 (2d8+13/19-20 plus poison), tentacles +25 (2d6+6 plus <Link to="/umr/grab">grab</Link> and poison)</>} space={"20"} reach={"20"} specAtt={[["self-evisceration","self-evisceration"],["spiny slam","spiny slam"],["tentacle grip","tentacle grip"]]} capsize swallow="6d6+19 bludgeoning damage, AC 18, 20 hp" />
