<Stats id="monster-automaton_master_automaton--stats" atts={[28,16,0,20,21,27]} bab={25} cmb={36} cmd={58} feats={["Alertness","Combat Expertise","Combat Reflexes","Dodge","Flyby Attack","Hover",["Improved Critical"," (arcane hook)"],"Iron Will","Mobility","Power Attack","Spring Attack","Vital Strike",["Weapon Focus"," (arcane hook)"]]} skills={{"climb":{"b":32},"intm":{"b":23},"k":{"a":30},"per":{"b":34},"sm":{"b":7},"spc":{"b":20},"umd":{"b":23}}} lang={["A","Ce","C","Ig",["Jistka"],";",[<><Link to="/umr/telepathy">telepathy</Link> 100 ft., <em>tongues</em></>]]} />
